package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal.pensioenpijler2.validatie;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.pensioenpijler2.validatie.PensioenPijler2Validator;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.pensioenpijler2.validatie.PensioenPijler2Validator2010;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.VrijstelPens2;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;

import java.util.Arrays;
import java.util.List;

public class PensioenPijler2ValidatorDmfa2023 implements PensioenPijler2Validator {
    public static final int PROVANT_0_PRCT = 89;
    private static final List<VrijstelPens2> TOEGELATEN_VRIJSTELLINGEN_PENS_2_PROVANT_0_PRCT =
            Arrays.asList(VrijstelPens2.NVT, VrijstelPens2.WEL_VRIJSTELLING, VrijstelPens2.WN_PROVANT_0_PCT);
    private final ConstantManager constantManager;
    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;
    private final VrijstelPens2 vrijstellingTweedePensioenpijler;
    private final Opper opper;
    private final RekenTijd rekenTijd;
    private final RegulManager regulManager;

    public PensioenPijler2ValidatorDmfa2023(
            ConstantManager constantManager, DmfapplBasisBijdrageService dmfapplBasisBijdrageService, Opper opper, RekenTijd rekenTijd, RegulManager regulManager) {
        this.constantManager = constantManager;
        this.dmfapplBasisBijdrageService = dmfapplBasisBijdrageService;
        this.opper = opper;
        this.rekenTijd = rekenTijd;
        this.regulManager = regulManager;

        Rszppo rszppo = opper.getRszppo();
        vrijstellingTweedePensioenpijler = rszppo.getVrijstellingTweedePensioenpijler();
    }

    @Override
    public void validate() {
        PensioenPijler2Validator2010 pensioenPijler2Validator2010 =
                new PensioenPijler2Validator2010(constantManager, dmfapplBasisBijdrageService, opper, rekenTijd, regulManager);
        pensioenPijler2Validator2010.validate();

        validateDmfa2023();
    }

    private void validateDmfa2023() {
        controleerTypeBijdragePens2();
    }

    void controleerTypeBijdragePens2() {
        Constant typeBijdragePens2Constante = constantManager.getActualConstant(Konstanten.KST_TYPE_BIJDRAGE_PENS2, rekenTijd);
        controleerToepassingsgebied(typeBijdragePens2Constante.getInteger());
    }

    void controleerToepassingsgebied(int typeBijdragePens2) {
        if (typeBijdragePens2 == PROVANT_0_PRCT
                && !TOEGELATEN_VRIJSTELLINGEN_PENS_2_PROVANT_0_PRCT.contains(vrijstellingTweedePensioenpijler)) {
            regulManager.doRegulException(opper.getOpdracht(), Regulkode.ONGELDIG_TOEPASSINGSGEBIED);
        }
    }
}
